// ---------------------------------------------------------------------------
// snippetPopover.ts
// Tiny controller for the "copy equation / code snippet" popover used
// by curve cards and the detail page. Lazily finds or creates the
// #copy-popover host, renders the per-target snippet list, handles
// outside-click and Escape-to-close, and copies the selected snippet
// to the clipboard. Module-level singletons — one popover per page.
// ---------------------------------------------------------------------------

export type SnippetMap = Record<string, string>;

const POPOVER_ID = "copy-popover";

let popover: HTMLElement | null = null;
let activeToggle: HTMLElement | null = null;

const getPopover = (): HTMLElement => {
  if (!popover) {
    popover = document.getElementById(POPOVER_ID);
    if (!popover) {
      popover = document.createElement("div");
      popover.id = POPOVER_ID;
      popover.setAttribute("data-copy-popover", "");
      document.body.appendChild(popover);
    }
  }
  return popover;
};

